<?php
namespace App\Modules\Hr\Recruitment\Models; use App\Modules\Hr\Core\Traits\BelongsToLegalEntity; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Relations\BelongsTo; use Illuminate\Database\Eloquent\Relations\HasMany; use Illuminate\Database\Eloquent\Relations\HasOne;
class HrApplication extends Model{use BelongsToLegalEntity;protected $fillable=['legal_entity_id','job_posting_id','candidate_id','current_stage','status','human_score','summary','decision_reason','decided_by','decided_at'];protected function casts():array{return ['human_score'=>'decimal:2','decided_at'=>'datetime'];}public function posting():BelongsTo{return $this->belongsTo(HrJobPosting::class,'job_posting_id');}public function candidate():BelongsTo{return $this->belongsTo(HrCandidate::class,'candidate_id');}public function stages():HasMany{return $this->hasMany(HrApplicationStage::class,'application_id');}public function offer():HasOne{return $this->hasOne(HrJobOffer::class,'application_id');}}
